// apps/web/src/apolloClient.ts
import { ApolloClient, InMemoryCache, createHttpLink, ApolloLink } from '@apollo/client';
import { setContext } from '@apollo/client/link/context';
import { getGraphQLEndpoint } from './lib/urlUtils';

// Day 1 Tech Focus: Understanding the Front-end Client and Gateway proxy
// The check-in web application communicates with Amadeus via our Fastify API proxy.
const httpLink = createHttpLink({
  uri: getGraphQLEndpoint(), // Resolves to Next.js /api/graphql -> Fastify backend
});

// Authentication link injects the JWT token (backendToken) issued during sign-in
const authLink = setContext((_, { headers }) => {
  const sessionToken = typeof window !== 'undefined' 
    ? localStorage.getItem('gc_backend_token') 
    : null;

  return {
    headers: {
      ...headers,
      authorization: sessionToken ? `Bearer ${sessionToken}` : '',
      'X-Airline-Code': 'VA', // Virgin Australia identifier
      'X-Channel-ID': 'WEB_CHECKIN' // Identifies source of Amadeus PSS traffic
    }
  };
});

export const client = new ApolloClient({
  link: authLink.concat(httpLink),
  cache: new InMemoryCache({
    typePolicies: {
      Passenger: {
        keyFields: ['pnr', 'lastName'], // PNR (Passenger Name Record) is our primary domain key
      },
      FlightSegment: {
        keyFields: ['flightNumber', 'departureDate', 'origin'],
      }
    }
  })
});

