import Redis from 'ioredis';
import { createOTelCounter } from '../utils/monitoring';

// Day 3 Tech Focus: Circuit Breakers and Redis caching for downstream PSS calls
const redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');
const seatMapFailCounter = createOTelCounter('seat_map_amadeus_failures');

export class ResilientSeatMapService {
  private static CIRCUIT_BREAKER_OPEN = false;
  private static LAST_FAILURE_TIME = 0;
  private static COOLDOWN_MS = 10000; // 10 seconds circuit trip

  static async getSeatMap(flightSegmentId: string): Promise<any> {
    // 1. Check Circuit status
    if (this.CIRCUIT_BREAKER_OPEN) {
      if (Date.now() - this.LAST_FAILURE_TIME > this.COOLDOWN_MS) {
        console.warn('🔌 Circuit entering half-open state, testing Amadeus...');
        this.CIRCUIT_BREAKER_OPEN = false;
      } else {
        console.error('🔌 Circuit is OPEN. Serving cached fallback seat layout...');
        return this.getCachedSeatMap(flightSegmentId);
      }
    }

    // 2. Query cache first to avoid overloading Amadeus
    const cachedData = await redis.get(`seatmap:${flightSegmentId}`);
    if (cachedData) {
      return JSON.parse(cachedData);
    }

    // 3. Downstream call with defensive timeout
    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 2500); // 2.5s maximum budget

      const response = await fetch(`${process.env.AMADEUS_API_BASE}/seatmap/${flightSegmentId}`, {
        signal: controller.signal
      });
      clearTimeout(timeout);

      if (!response.ok) throw new Error('Amadeus returned non-200 status');

      const freshMap = await response.json();

      // Save in cache with 2-minute TTL (highly dynamic, but buffers concurrent hits)
      await redis.setex(`seatmap:${flightSegmentId}`, 120, JSON.stringify(freshMap));
      return freshMap;

    } catch (error) {
      // Trip Circuit Breaker and serve fallback
      this.CIRCUIT_BREAKER_OPEN = true;
      this.LAST_FAILURE_TIME = Date.now();
      seatMapFailCounter.add(1, { flight: flightSegmentId });

      console.error('❌ Amadeus Seatmap connection failed. Tripping circuit.');
      return this.getCachedSeatMap(flightSegmentId);
    }
  }

  private static async getCachedSeatMap(flightId: string): Promise<any> {
    // Retrieve stale cache if available, or construct standard base physical aircraft configuration
    const stale = await redis.get(`seatmap:${flightId}`);
    if (stale) return JSON.parse(stale);

    // Ultimate fallback to avoid blank screen: return general seat configuration
    return { fallback: true, rows: 30, configuration: '3-3' };
  }
}

