// Day 4 Tech Focus: Schema contracts and secure PII handling for baggage registration
const express = require('express');
const { encryptSensitiveData } = require('../services/cryptoService'); // Compliant PII encryption

const router = express.Router();

router.post('/register-bags', async (req, res) => {
  const { pnr, passengerId, bags, dangerousGoodsConfirmed, passportData } = req.body;

  // 1. Safety Rule: Strict validation for Dangerous Goods compliance
  if (!dangerousGoodsConfirmed) {
    return res.status(400).json({
      error: 'DANGEROUS_GOODS_DECLARATION_REQUIRED',
      message: 'Passengers must explicitly declare that they are not carrying hazardous materials.'
    });
  }

  // 2. Validate Baggage Allowance Rules based on tier
  const invalidBags = bags.filter(bag => bag.weight > 32); // Absolute safety limit for ground handler health
  if (invalidBags.length > 0) {
    return res.status(400).json({
      error: 'EXCESSIVE_BAG_WEIGHT',
      message: 'No single bag can exceed 32kg due to airport workplace health and safety rules.'
    });
  }

  try {
    // 3. Encrypt Sensitive PII (Passport Details) before forwarding to DB or Amadeus log pools
    let securePassport = null;
    if (passportData) {
      securePassport = encryptSensitiveData(JSON.stringify(passportData));
    }

    // 4. Interface with the PSS Baggage API (abstracted SOAP Altéa check-in call)
    console.log(`✈️ Registering ${bags.length} bags for PNR ${pnr}...`);

    // Return success payload matching our unified schema
    res.status(200).json({
      success: true,
      pnr,
      bagTags: bags.map((bag, i) => `VA-${pnr}-${passengerId}-${i + 1}`),
      allowanceStatus: 'VERIFIED'
    });
  } catch (error) {
    console.error('Failed to register bags:', error);
    res.status(500).json({ error: 'PSS_BAGGAGE_REGISTRATION_FAILED' });
  }
});

module.exports = router;
